import React from 'react';
import { Link } from 'react-router-dom';

export default function Links(props) {
  return (
    <div className="links">
      {props.links.map(link => {
        if (link.url.includes('http'))
          return (
            <a className="linky" key={link.title} href={link.url}>
              {link.title}
            </a>
          );
        else {
          return (
            <Link className="linky" key={link.title} to={link.url}>
              {link.title}
            </Link>
          );
        }
      })}
    </div>
  );
}



